// Extrair o texto da resposta da IA
const outputArray = $json.output;
const message = outputArray[0];
const textContent = message.content[0].text;

// Verificar se a resposta está completa
if (message.status !== "completed") {
  return {
    erro: "Resposta da IA incompleta",
    status: message.status,
    processo_id: $json.processo_id,
    numero_processo: $json.numero_processo
  };
}

// Remover os marcadores de markdown ```json e ```
const jsonString = textContent
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

// Fazer parse do JSON
let parsedData;
try {
  parsedData = JSON.parse(jsonString);
} catch (e) {
  return {
    erro: "Falha ao parsear JSON",
    mensagem: e.message,
    processo_id: $json.processo_id,
    numero_processo: $json.numero_processo
  };
}

// Validar e garantir que cada chunk tenha os campos necessários
const chunksValidados = parsedData.chunks.map(chunk => ({
  ordem: chunk.ordem,
  tema: chunk.tema,
  tema_sugerido: chunk.tema_sugerido || null,
  resumo: chunk.resumo,
  texto: chunk.texto
}));

// Retornar os dados do processo junto com os chunks parseados
return {
  id: $json.id,
  processo_id: $json.processo_id,
  numero_processo: $json.numero_processo,
  data_processo: $json.data_processo,
  arquivo_id: $json.arquivo_id,
  chunks: chunksValidados
};

